# 图片文件路径 (你刚才用脚本生成的拼图)
INPUT_MAP = "test_map_z12.png"
OUTPUT_MAP = "map_with_markers.png"


# ============================================

def draw_markers():
    try:
        img = Image.open(INPUT_MAP).convert("RGBA")
    except FileNotFoundError:
        print(f"找不到地图文件 {INPUT_MAP}，请确认！")
        return

    draw = ImageDraw.Draw(img)

    # 建立一个字典作为“图标缓存库”，避免重复从硬盘读取相同的图片
    icon_cache = {}

    for item in points_data:
        lat = item["point"]["lat"]
        lng = item["point"]["lng"]
        mark_type = item.get("markType")  # 获取 markType，例如 701
        title = item.get("title", "未命名点位")

        # --- 1. 坐标缩放与换算 ---
        scaled_lng = lng * SCALE
        scaled_lat = lat * SCALE
        pixel_x = scaled_lng - (X_MIN * TILE_SIZE)
        pixel_y = scaled_lat - (Y_MIN * TILE_SIZE)

        print(f"[{title}] 最终像素坐标({pixel_x}, {pixel_y})")

        # --- 2. 绘制图标逻辑 ---
        icon = None
        if mark_type is not None:
            # 拼接图标文件的路径，比如 "img/701.png"
            # 注意：请确保你的代码同级目录下有一个叫 img 的文件夹！
            icon_path = os.path.join("img", f"{mark_type}.png")

            # 如果这个图标还没被加载过，尝试读取它
            if mark_type not in icon_cache:
                if os.path.exists(icon_path):
                    # 读取图片，并转换为带透明通道的 RGBA 模式
                    icon_cache[mark_type] = Image.open(icon_path).convert("RGBA")
                else:
                    # 如果 img 文件夹下没有这张图，标记为 None
                    print(f"  [警告] 找不到对应的图标文件: {icon_path}")
                    icon_cache[mark_type] = None

            # 从缓存里拿出图标对象
            icon = icon_cache[mark_type]

        # 3. 将图标贴到大图上
        if icon:
            # --- 1. 缩小图标 ---
            # 假设你想把图标统一缩小到宽 20 像素 (保持长宽比)
            new_width = 30
            # 计算缩放后的高度
            new_height = int((new_width / icon.width) * icon.height)
            # 缩放图片 (LANCZOS 是最高质量的缩放算法)
            icon = icon.resize((new_width, new_height), Image.Resampling.LANCZOS)

            # --- 2. 修改图标透明度 ---
            # 提取图片的四个通道：红、绿、蓝、透明度(alpha)
            r, g, b, alpha = icon.split()
            # 将现有的透明度乘以一个系数，比如 0.6 (即 60% 的不透明度)
            alpha = alpha.point(lambda p: p * 0.8)
            # 重新把透明通道放回去
            icon.putalpha(alpha)

            # --- 3. 居中粘贴 ---
            paste_x = int(pixel_x - icon.width / 2)
            paste_y = int(pixel_y - icon.height / 2)
            img.paste(icon, (paste_x, paste_y), mask=icon)
        else:
            # 作为“备用方案(Fallback)”：
            # 如果 json 里没有 markType，或者 img 文件夹里缺了这张图，就在地图上画个红点代替
            r = 10
            draw.ellipse((pixel_x - r, pixel_y - r, pixel_x + r, pixel_y + r), fill="red", outline="white", width=2)

    img.save(OUTPUT_MAP)
    print(f"✅ 绘制完成！请查看 {OUTPUT_MAP}")


if __name__ == "__main__":
    draw_markers()